// Auto-generated vehicle detection images
const BASE64_IMAGES = {
  "city_road": "data:image/svg+xml;base64,",
  "night_traffic": "data:image/svg+xml;base64,",
  "highway": "data:image/svg+xml;base64,",
  "motorway": "data:image/svg+xml;base64,",
  "street": "data:image/svg+xml;base64,",
  "bus": "data:image/svg+xml;base64,",
  "truck": "data:image/svg+xml;base64,",
  "sport_car": "data:image/svg+xml;base64,"
};


// Auto-initialize when DOM is ready
if (typeof document !== "undefined") {
    document.addEventListener("DOMContentLoaded", function() {
        for (const [name, src] of Object.entries(BASE64_IMAGES)) {
            const img = document.getElementById("gallery-" + name);
            if (img && src) {
                img.src = src;
                img.onload = function() { this.classList.add("loaded"); };
                img.onerror = function() { this.classList.add("loaded"); };
            }
        }
    });
}
